  bg: "#F8F6F3", card: "#FFFFFF", ink: "#1A1816", muted: "#8C857A",
  accent: "#C45D3E", accentHover: "#B04E32", accentSoft: "rgba(196,93,62,.07)",
  border: "#E8E4DF", borderFocus: "#C45D3E",
  gold: "#D4A853", goldSoft: "rgba(212,168,83,.10)",
  green: "#3A8A5C", greenSoft: "rgba(58,138,92,.08)",
  red: "#C0392B", redSoft: "rgba(192,57,43,.07)",
  shadow: "0 1px 3px rgba(26,24,22,.05), 0 4px 12px rgba(26,24,22,.04)",
  shadowLg: "0 2px 8px rgba(26,24,22,.06), 0 12px 32px rgba(26,24,22,.08)",
